#include <stdio.h>
#include <math.h>
int isPrime(int n) {
    if (n <= 1) return 0;
    for (int i = 2; i <= sqrt(n); i++) {
        if (n % i == 0) return 0;
    }
    return 1;
}
int main() {
    int T, n, ai, product;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        product = 1;
        for (int i = 0; i < n; i++) {
            scanf("%d", &ai);
            if (isPrime(ai)) product *= ai;
        }
        printf("%d\n", product);
    }
    return 0;
}

