import math

def isPrime(n):
    if n <= 1: return False
    for i in range(2, int(math.sqrt(n)) + 1):
        if n % i == 0: return False
    return True

def main():
    T = int(input())
    for _ in range(T):
        n = int(input())
        product = 1
        ai_list = list(map(int, input().split()))
        for ai in ai_list:
            if isPrime(ai): product *= ai
        print(product)

def solution():
    main()
if __name__ == '__main__':
    solution()

